// ─── SECURE API ───────────────────────────────────────────────────────────────
// All Supabase credentials live in Vercel environment variables (server-side)
// The frontend only talks to our own /api/* endpoints

let _adminToken = null;

const sb = {
  setToken(token) { _adminToken = token; },
  clearToken() { _adminToken = null; },

  async getSetting(key) {
    const r = await fetch(`/api/settings?key=${key}`);
    if (!r.ok) return null;
    const data = await r.json();
    return data?.value ?? null;
  },

  async setSetting(key, value) {
    await fetch(`/api/settings?key=${key}`, {
      method: "POST",
      headers: { "Content-Type": "application/json", "x-admin-token": _adminToken },
      body: JSON.stringify({ value })
    });
  },

  async getRequests() {
    const r = await fetch("/api/requests", {
      headers: { "x-admin-token": _adminToken }
    });
    if (!r.ok) return [];
    return r.json();
  },

  async addRequest(req) {
    const r = await fetch("/api/requests", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(req)
    });
    return r.json();
  },

  async updateRequest(id, status, extra={}) {
    await fetch(`/api/requests?id=${id}`, {
      method: "PATCH",
      headers: { "Content-Type": "application/json", "x-admin-token": _adminToken },
      body: JSON.stringify({ status, ...extra })
    });
  },

  async login(password) {
    const r = await fetch("/api/login", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ password })
    });
    if (!r.ok) return null;
    const data = await r.json();
    return data?.token ?? null;
  }
};

