// ─── CALENDAR ─────────────────────────────────────────────────────────────────

function Calendar({ blockedDates, ownerDates=[], airbnbDates=[], onSelectRange, selectedStart, selectedEnd, readOnly=false, compact=false }) {
  const today = new Date();
  const [viewYear, setViewYear] = useState(today.getFullYear());
  const [viewMonth, setViewMonth] = useState(today.getMonth());
  const [hover, setHover] = useState(null);
  const blockedSet = new Set(blockedDates);
  const airbnbSet = new Set(airbnbDates);
  const ownerSet = new Set(ownerDates);

  function toISO(y,m,d){ return `${y}-${String(m+1).padStart(2,"0")}-${String(d).padStart(2,"0")}`; }
  function daysInMonth(y,m){ return new Date(y,m+1,0).getDate(); }
  function firstDay(y,m){ return (new Date(y,m,1).getDay()+6)%7; }

  function getState(iso){
    const d=new Date(iso), todayISO=today.toISOString().slice(0,10);
    if(airbnbSet.has(iso)) return "airbnb";
    if(blockedSet.has(iso)) return "blocked";
    if(ownerSet.has(iso)) return "owner";
    if(d<new Date(todayISO)) return "past";
    if(iso===selectedStart||iso===selectedEnd) return "selected";
    if(selectedStart&&selectedEnd&&iso>selectedStart&&iso<selectedEnd) return "range";
    if(selectedStart&&!selectedEnd&&hover&&iso>selectedStart&&iso<=hover) return "hover";
    return "free";
  }

  function handleClick(iso){
    if(readOnly||blockedSet.has(iso)||ownerSet.has(iso)||airbnbSet.has(iso)) return;
    if(new Date(iso)<new Date(today.toISOString().slice(0,10))) return;
    onSelectRange(iso);
  }

  const days=daysInMonth(viewYear,viewMonth), start=firstDay(viewYear,viewMonth);
  const season=getSeason(viewMonth);
  const seasonLabel={low:"Low season",mid:"Mid season",peak:"Peak summer"}[season];
  const seasonColor={low:"#ffdad5",mid:"#c8dfc8",peak:"#ffdad5"}[season];

  return (
    <div style={{userSelect:"none"}}>
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:"1rem"}}>
        <button onClick={()=>viewMonth===0?setViewMonth(11)||setViewYear(y=>y-1):setViewMonth(m=>m-1)}
          style={{background:C.surfaceContainerLow,border:"none",borderRadius:"8px",padding:"6px 12px",cursor:"pointer",display:"flex",alignItems:"center"}}>
          <Icon name="chevron_left" size={20}/>
        </button>
        <div style={{textAlign:"center"}}>
          <div style={{fontFamily:"'Plus Jakarta Sans',sans-serif",fontWeight:"700",fontSize:"1rem"}}>{MONTHS[viewMonth]} {viewYear}</div>
          <span style={{background:seasonColor,color:C.onPrimaryFixed,fontSize:"0.65rem",fontWeight:"700",padding:"2px 10px",borderRadius:"999px",letterSpacing:"0.05em",textTransform:"uppercase"}}>{seasonLabel}</span>
        </div>
        <button onClick={()=>viewMonth===11?setViewMonth(0)||setViewYear(y=>y+1):setViewMonth(m=>m+1)}
          style={{background:C.surfaceContainerLow,border:"none",borderRadius:"8px",padding:"6px 12px",cursor:"pointer",display:"flex",alignItems:"center"}}>
          <Icon name="chevron_right" size={20}/>
        </button>
      </div>

      <div style={{display:"grid",gridTemplateColumns:"repeat(7,1fr)",gap:"2px",marginBottom:"4px"}}>
        {["Mo","Tu","We","Th","Fr","Sa","Su"].map(d=>(
          <div key={d} style={{textAlign:"center",fontSize:"0.65rem",fontWeight:"800",color:C.onSurfaceVariant,padding:"4px 0",letterSpacing:"0.05em",textTransform:"uppercase"}}>{d}</div>
        ))}
      </div>
      <div style={{display:"grid",gridTemplateColumns:"repeat(7,1fr)",gap:"2px"}}>
        {Array(start).fill(null).map((_,i)=><div key={"e"+i}/>)}
        {Array(days).fill(null).map((_,i)=>{
          const day=i+1, iso=toISO(viewYear,viewMonth,day), state=getState(iso);
          const isWknd=((start+i)%7)>=5;
          const bg=state==="airbnb"?"#d4edda":state==="blocked"?"#ffdad5":state==="owner"?"#fff3cd":state==="past"?"transparent":state==="selected"?C.secondary:state==="range"||state==="hover"?"#dfe0ff":isWknd?C.surfaceContainerLow:C.surfaceContainerLowest;
          const color=state==="airbnb"?"#155724":state==="blocked"?"#930006":state==="owner"?"#856404":state==="past"?"#c0b8b0":state==="selected"?"white":C.onSurface;
          const fw=state==="selected"?"700":"400";
          return (
            <div key={iso}
              onClick={()=>handleClick(iso)}
              onMouseEnter={()=>!readOnly&&setHover(iso)}
              onMouseLeave={()=>!readOnly&&setHover(null)}
              style={{
                textAlign:"center",padding:compact?"5px 2px":"7px 2px",borderRadius:"6px",
                background:bg,color,cursor:readOnly||state==="blocked"||state==="past"?"default":"pointer",
                fontSize:"0.82rem",fontWeight:fw,
                border:state==="selected"?`2px solid ${C.primary}`:"2px solid transparent",
                transition:"background 0.1s",position:"relative",
              }}>
              {day}
              {state==="blocked"&&<div style={{position:"absolute",bottom:"2px",left:"50%",transform:"translateX(-50%)",width:"4px",height:"4px",borderRadius:"50%",background:"#930006"}}/>}
              {state==="owner"&&<div style={{position:"absolute",bottom:"2px",left:"50%",transform:"translateX(-50%)",width:"4px",height:"4px",borderRadius:"50%",background:"#856404"}}/>}
            </div>
          );
        })}
      </div>
      <div style={{display:"flex",gap:"12px",marginTop:"0.75rem",flexWrap:"wrap"}}>
        {[[C.surfaceContainerLowest,"Available",C.outlineVariant],[C.primaryFixed,"Booked","#ffb4aa"],["#fff3cd","Vincent's stay","#ffc107"],["#dfe0ff","Selected","#bcc2ff"]].map(([bg,label,border])=>(
          <div key={label} style={{display:"flex",alignItems:"center",gap:"5px",fontSize:"0.7rem",color:C.onSurfaceVariant}}>
            <div style={{width:"10px",height:"10px",borderRadius:"2px",background:bg,border:`1px solid ${border}`}}/>
            <span>{label}</span>
          </div>
        ))}
      </div>
    </div>
  );
}

// ─── COOKIE BANNER ───────────────────────────────────────────────────────────

function CookieBanner() {
  const [visible, setVisible] = useState(() => {
    try { return !localStorage.getItem("tcf_cookies_accepted"); }
    catch(e) { return true; }
  });

  function accept() {
    try { localStorage.setItem("tcf_cookies_accepted", "1"); } catch(e) {}
    setVisible(false);
  }

  function decline() {
    try { localStorage.setItem("tcf_cookies_accepted", "0"); } catch(e) {}
    setVisible(false);
  }

  if (!visible) return null;

  return (
    <div style={{
      position:"fixed", bottom:0, left:0, right:0, zIndex:99999,
      background:"rgba(10,15,46,0.97)", backdropFilter:"blur(8px)",
      padding:"16px 24px", display:"flex", alignItems:"center",
      justifyContent:"space-between", flexWrap:"wrap", gap:"12px",
      borderTop:"2px solid rgba(220,36,31,0.4)"
    }}>
      <div style={{flex:1, minWidth:"260px"}}>
        <p style={{color:"white", fontSize:"0.85rem", lineHeight:"1.6", margin:0}}>
          🍪 We use cookies to remember your preferences and improve your experience.
          By using this site you agree to our Privacy Policy.
        </p>
      </div>
      <div style={{display:"flex", gap:"8px", flexShrink:0}}>
        <button onClick={decline} style={{
          background:"transparent", border:"1px solid rgba(255,255,255,0.3)",
          color:"rgba(255,255,255,0.7)", borderRadius:"6px", padding:"7px 16px",
          fontSize:"0.82rem", cursor:"pointer", fontWeight:"500"
        }}>Decline</button>
        <button onClick={accept} style={{
          background:"linear-gradient(135deg,#b6000a,#dc241f)",
          border:"none", color:"white", borderRadius:"6px", padding:"7px 18px",
          fontSize:"0.82rem", cursor:"pointer", fontWeight:"700"
        }}>Accept cookies</button>
      </div>
    </div>
  );
}

