// ─── GUEST: BOOK ──────────────────────────────────────────────────────────────

function GuestBook({ blockedDates, ownerDates, pricing, onSubmitRequest }) {
  const [selStart,setSelStart]=useState(null);
  const [selEnd,setSelEnd]=useState(null);
  const [form,setForm]=useState({name:"",email:"",phone:"",relationship:"",message:""});
  const [submitted,setSubmitted]=useState(false);
  const [loading,setLoading]=useState(false);
  const [error,setError]=useState("");

  function handleRange(iso){
    if(!selStart||(selStart&&selEnd)){setSelStart(iso);setSelEnd(null);}
    else{
      if(iso<selStart){setSelStart(iso);setSelEnd(null);}
      else if(iso===selStart) setSelStart(null);
      else{
        const range=dateRange(selStart,iso);
        if(range.some(d=>new Set(blockedDates).has(d))){setError("Selection includes unavailable dates.");return;}
        setSelEnd(iso);setError("");
      }
    }
  }

  function calcPrice(){
    if(!selStart||!selEnd) return null;
    const nights=Math.round((new Date(selEnd)-new Date(selStart))/86400000);
    const season=getSeason(new Date(selStart).getMonth());
    const ni=getNightIndex(nights);
    return{nights,season,total:pricing[season].direct[ni]*nights,perNight:pricing[season].direct[ni],seasonLabel:pricing[season].label};
  }
  const pc=calcPrice();

  async function handleSubmit(){
    if(!selStart||!selEnd) return setError("Please select your dates first.");
    if(!form.name) return setError("Please enter your name.");
    if(!form.email) return setError("Please enter your email.");
    setLoading(true);setError("");
    try{
      await onSubmitRequest({name:form.name,email:form.email,phone:form.phone,relationship:form.relationship,message:form.message,check_in:selStart,check_out:selEnd,nights:pc?.nights,total:pc?.total,season:pc?.season,status:"pending"});
      setSubmitted(true);
    }catch(e){setError("Something went wrong. Please try again.");}
    setLoading(false);
  }

  if(submitted) return (
    <div style={{padding:"120px 48px 80px",maxWidth:"640px",margin:"0 auto",textAlign:"center"}} className="fade-in">
      <div style={{width:"64px",height:"64px",borderRadius:"50%",background:"#e8f5e8",display:"flex",alignItems:"center",justifyContent:"center",margin:"0 auto 24px"}}>
        <Icon name="check_circle" size={32} fill={1} style={{color:"#1a6a1a"}}/>
      </div>
      <h2 style={{fontFamily:"'Plus Jakarta Sans',sans-serif",fontSize:"2rem",fontWeight:"800",marginBottom:"12px"}}>Request sent!</h2>
      <p style={{color:C.onSurfaceVariant,lineHeight:"1.7",marginBottom:"32px"}}>Thanks {form.name}! We'll get back to you at <strong>{form.email}</strong> within 24 hours to confirm your stay.</p>
      <button className="btn-primary" onClick={()=>{setSubmitted(false);setSelStart(null);setSelEnd(null);setForm({name:"",email:"",phone:"",relationship:"",message:""});}}>Make another request</button>
    </div>
  );

  return (
    <div className="fade-in" style={{padding:"120px clamp(20px,5vw,48px) 80px",maxWidth:"1280px",margin:"0 auto"}}>
      <div style={{marginBottom:"48px"}}>
        <span style={{display:"inline-flex",alignItems:"center",gap:"8px",background:C.primaryFixed,color:C.onPrimaryFixed,padding:"4px 16px",borderRadius:"999px",fontSize:"0.72rem",fontWeight:"800",letterSpacing:"0.1em",textTransform:"uppercase",marginBottom:"16px"}}>
          <span style={{width:"8px",height:"8px",borderRadius:"50%",background:C.primary}}/>
          Direct Booking
        </span>
        <h1 style={{fontFamily:"'Plus Jakarta Sans',sans-serif",fontSize:"3rem",fontWeight:"800",letterSpacing:"-0.02em",marginBottom:"8px"}}>Request a Stay</h1>
        <p style={{color:C.onSurfaceVariant}}>Select your dates and we'll confirm within 24 hours. No payment needed upfront.</p>
      </div>

      {error&&<div style={{background:"#ffdad5",border:"1px solid #ffb4aa",borderRadius:"8px",padding:"12px 16px",marginBottom:"24px",color:"#930006",fontSize:"0.9rem"}} role="alert">{error}</div>}

      <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(300px,1fr))",gap:"32px"}}>
        <div className="card" style={{padding:"32px"}}>
          <h3 style={{fontFamily:"'Plus Jakarta Sans',sans-serif",fontWeight:"700",marginBottom:"20px",fontSize:"1rem",textTransform:"uppercase",letterSpacing:"0.06em",color:C.onSurfaceVariant}}>① Select dates</h3>
          <Calendar blockedDates={blockedDates} ownerDates={ownerDates} airbnbDates={airbnbDates} onSelectRange={handleRange} selectedStart={selStart} selectedEnd={selEnd}/>
          {selStart&&!selEnd&&<p style={{marginTop:"12px",fontSize:"0.82rem",color:C.onSurfaceVariant}}>Now click your check-out date</p>}
          {pc&&(
            <div style={{marginTop:"16px",background:C.surfaceContainerLow,borderRadius:"10px",padding:"16px"}}>
              <div style={{display:"flex",justifyContent:"space-between",fontSize:"0.85rem",marginBottom:"6px"}}>
                <span style={{color:C.onSurfaceVariant}}>{formatDate(selStart)} → {formatDate(selEnd)}</span>
                <span style={{fontWeight:"600"}}>{pc.nights} nights</span>
              </div>
              <div style={{display:"flex",justifyContent:"space-between",alignItems:"baseline"}}>
                <span style={{fontSize:"0.8rem",color:C.onSurfaceVariant}}>{pc.seasonLabel} · direct rate</span>
                <span style={{fontFamily:"'Plus Jakarta Sans',sans-serif",fontSize:"1.5rem",fontWeight:"800",color:C.primary}}>£{pc.total}</span>
              </div>
            </div>
          )}
        </div>

        <div className="card" style={{padding:"32px"}}>
          <h3 style={{fontFamily:"'Plus Jakarta Sans',sans-serif",fontWeight:"700",marginBottom:"20px",fontSize:"1rem",textTransform:"uppercase",letterSpacing:"0.06em",color:C.onSurfaceVariant}}>② Your details</h3>
          {[["name","Your name","text","e.g. Sarah",true],["email","Email address","email","sarah@email.com",true],["phone","Phone","tel","+44 ...",false],["relationship","Your relationship to Vincent or Elina","text","e.g. friend, colleague, family...",true]].map(([f,label,type,ph,req])=>(
            <div key={f} style={{marginBottom:"14px"}}>
              <label htmlFor={`b-${f}`} style={{display:"block",fontSize:"0.78rem",fontWeight:"600",color:C.onSurfaceVariant,marginBottom:"5px"}}>{label}{req&&<span style={{color:C.error}}> *</span>}</label>
              <input id={`b-${f}`} type={type} placeholder={ph} value={form[f]} required={req}
                onChange={e=>setForm(prev=>({...prev,[f]:e.target.value}))}
                className="input-field"/>
            </div>
          ))}
          <div style={{marginBottom:"20px"}}>
            <label htmlFor="b-msg" style={{display:"block",fontSize:"0.78rem",fontWeight:"600",color:C.onSurfaceVariant,marginBottom:"5px"}}>Message (optional)</label>
            <textarea id="b-msg" placeholder="Any questions or special requests..." value={form.message}
              onChange={e=>setForm(prev=>({...prev,message:e.target.value}))}
              className="input-field" style={{height:"80px",resize:"vertical"}}/>
          </div>
          <button className="btn-primary" onClick={handleSubmit} disabled={loading||!selStart||!selEnd}
            style={{width:"100%",padding:"14px",fontSize:"1rem",opacity:!selStart||!selEnd?0.5:1,cursor:!selStart||!selEnd?"not-allowed":"pointer"}}>
            {loading?"Sending…":"Send booking request →"}
          </button>
          <p style={{fontSize:"0.75rem",color:C.onSurfaceVariant,marginTop:"8px",textAlign:"center"}}>No payment needed now · We'll confirm within 24h</p>
        </div>
      </div>
    </div>
  );
}



// ─── ADMIN: GUESTBOOK ────────────────────────────────────────────────────────

function AdminGuestbook({ entries, setEntries, flashSave }) {
  const [showAdd, setShowAdd] = useState(false);
  const [form, setForm] = useState({ name: "", date: new Date().toISOString().slice(0,10), story: "", nights: "" });

  async function addEntry() {
    if (!form.name || !form.story) return;
    const next = [...(entries||[]), { ...form, id: Date.now() }];
    setEntries(next);
    await sb.setSetting("guestbook", next);
    setShowAdd(false);
    setForm({ name: "", date: new Date().toISOString().slice(0,10), story: "", nights: "" });
    flashSave("Guestbook entry added ✓");
  }

  async function removeEntry(id) {
    const next = (entries||[]).filter(e => e.id !== id);
    setEntries(next);
    await sb.setSetting("guestbook", next);
    flashSave("Entry removed ✓");
  }

  return (
    <div className="slide-in">
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:"8px",flexWrap:"wrap",gap:"12px"}}>
        <div>
          <h2 style={{fontFamily:"'Plus Jakarta Sans',sans-serif",fontWeight:"700",fontSize:"1.3rem"}}>Guestbook</h2>
          <p style={{fontSize:"0.85rem",color:C.onSurfaceVariant,marginTop:"4px"}}>Add guest stories — they appear on the public Guestbook tab.</p>
        </div>
        <button onClick={()=>setShowAdd(s=>!s)} className="btn-primary" style={{display:"flex",alignItems:"center",gap:"6px",fontSize:"0.85rem"}}>
          <Icon name="add" size={16}/>Add entry
        </button>
      </div>

      {showAdd&&(
        <div className="card" style={{padding:"24px",marginBottom:"20px"}}>
          <h3 style={{fontFamily:"'Plus Jakarta Sans',sans-serif",fontWeight:"700",fontSize:"1rem",marginBottom:"16px"}}>New guestbook entry</h3>
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:"12px",marginBottom:"12px"}}>
            <div>
              <label style={{display:"block",fontSize:"0.72rem",fontWeight:"700",color:C.onSurfaceVariant,textTransform:"uppercase",letterSpacing:"0.06em",marginBottom:"4px"}}>Guest name</label>
              <input value={form.name} onChange={e=>setForm(f=>({...f,name:e.target.value}))} placeholder="e.g. Mick & Sarah" className="input-field"/>
            </div>
            <div>
              <label style={{display:"block",fontSize:"0.72rem",fontWeight:"700",color:C.onSurfaceVariant,textTransform:"uppercase",letterSpacing:"0.06em",marginBottom:"4px"}}>Date of stay</label>
              <input type="date" value={form.date} onChange={e=>setForm(f=>({...f,date:e.target.value}))} className="input-field"/>
            </div>
            <div>
              <label style={{display:"block",fontSize:"0.72rem",fontWeight:"700",color:C.onSurfaceVariant,textTransform:"uppercase",letterSpacing:"0.06em",marginBottom:"4px"}}>Nights stayed</label>
              <input type="number" value={form.nights} onChange={e=>setForm(f=>({...f,nights:e.target.value}))} placeholder="e.g. 3" className="input-field"/>
            </div>
          </div>
          <div style={{marginBottom:"12px"}}>
            <label style={{display:"block",fontSize:"0.72rem",fontWeight:"700",color:C.onSurfaceVariant,textTransform:"uppercase",letterSpacing:"0.06em",marginBottom:"4px"}}>Their story</label>
            <textarea value={form.story} onChange={e=>setForm(f=>({...f,story:e.target.value}))}
              placeholder="Paste their message here..." className="input-field" style={{height:"120px",resize:"vertical"}}/>
          </div>
          <div style={{display:"flex",gap:"8px",justifyContent:"flex-end"}}>
            <button onClick={()=>setShowAdd(false)} className="btn-ghost" style={{fontSize:"0.85rem"}}>Cancel</button>
            <button onClick={addEntry} className="btn-primary" style={{fontSize:"0.85rem"}}>Save entry</button>
          </div>
        </div>
      )}

      {(!entries||entries.length===0)
        ? <div className="card" style={{padding:"32px",textAlign:"center",color:C.onSurfaceVariant}}>No entries yet. Add your first guest story!</div>
        : [...(entries||[])].sort((a,b)=>new Date(b.date)-new Date(a.date)).map(e=>(
          <div key={e.id} className="card" style={{padding:"20px",marginBottom:"12px"}}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",gap:"12px"}}>
              <div style={{flex:1}}>
                <div style={{display:"flex",alignItems:"center",gap:"10px",marginBottom:"8px",flexWrap:"wrap"}}>
                  <span style={{fontFamily:"'Plus Jakarta Sans',sans-serif",fontWeight:"700",fontSize:"1rem"}}>{e.name}</span>
                  <span style={{fontSize:"0.78rem",color:C.onSurfaceVariant}}>{formatDate(e.date)}</span>
                  {e.nights&&<span style={{fontSize:"0.72rem",background:C.primaryFixed,color:C.onPrimaryFixed,padding:"2px 8px",borderRadius:"999px",fontWeight:"700"}}>{e.nights} nights</span>}
                </div>
                <p style={{color:C.onSurfaceVariant,lineHeight:"1.7",fontSize:"0.88rem",whiteSpace:"pre-wrap"}}>{e.story}</p>
              </div>
              <button onClick={()=>removeEntry(e.id)} style={{background:"none",border:"none",color:C.error,cursor:"pointer",fontSize:"0.8rem",flexShrink:0}}>✕ Remove</button>
            </div>
          </div>
        ))
      }
    </div>
  );
}

